import{_ as a,o as e,c as s,a0 as n}from"./chunks/framework.M0_h-cZU.js";const r=JSON.parse('{"title":"Nuxt3 學習筆記 - Ryan","description":"","frontmatter":{"title":"Nuxt3 學習筆記 - Ryan"},"headers":[],"relativePath":"pages/f2e/docVue/nuxt/nuxt3/nuxt3-03.md","filePath":"pages/f2e/docVue/nuxt/nuxt3/nuxt3-03.md"}'),l={name:"pages/f2e/docVue/nuxt/nuxt3/nuxt3-03.md"};function t(d,i,p,h,o,u){return e(),s("div",null,[...i[0]||(i[0]=[n('<h1 id="_3-使用-nuxi-建立第一個專案" tabindex="-1">3. 使用 nuxi 建立第一個專案 <a class="header-anchor" href="#_3-使用-nuxi-建立第一個專案" aria-label="Permalink to &quot;3. 使用 nuxi 建立第一個專案&quot;">​</a></h1><h2 id="_1-nuxi-是什麼" tabindex="-1">1. nuxi 是什麼？ <a class="header-anchor" href="#_1-nuxi-是什麼" aria-label="Permalink to &quot;1. nuxi 是什麼？&quot;">​</a></h2><p><code>nuxi</code> 全名為 <code>Nuxt Command Line Interface</code>，是由 <code>Nuxt</code> 提供開發的標準工具。 <code>nuxi</code> 是官方提供的 <code>Nuxt 命令列工具（CLI）</code>，用途與 <code>Vue CLI</code> 相似，用來初始化與操作 <code>Nuxt</code> 專案</p><h2 id="_2-建立第一個-nuxt-3-專案流程" tabindex="-1">2. 建立第一個 Nuxt 3 專案流程 <a class="header-anchor" href="#_2-建立第一個-nuxt-3-專案流程" aria-label="Permalink to &quot;2. 建立第一個 Nuxt 3 專案流程&quot;">​</a></h2><p>文章示範使用 <code>nuxi</code> 建立專案的基本步驟：</p><ul><li><h3 id="安裝-nuxi" tabindex="-1">安裝 nuxi <a class="header-anchor" href="#安裝-nuxi" aria-label="Permalink to &quot;安裝 nuxi&quot;">​</a></h3><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nuxi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><h3 id="新建專案" tabindex="-1">新建專案 <a class="header-anchor" href="#新建專案" aria-label="Permalink to &quot;新建專案&quot;">​</a></h3><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nuxi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-nuxt-app</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><details class="details custom-block"><summary>選項說明</summary><ul><li>當下 <code>nuxi</code> 版本：3.34.0 <h3 id="模式說明" tabindex="-1">模式說明 <a class="header-anchor" href="#模式說明" aria-label="Permalink to &quot;模式說明&quot;">​</a></h3><ul><li>content – Content-driven website <ul><li>專門做『內容網站 / 部落格』的模板 <ul><li>安裝 <code>@nuxt/content</code></li><li><code>Markdown</code> 驅動內容</li><li>文章路由、內容讀取機制</li></ul></li></ul></li><li>minimal – Minimal setup for Nuxt 4 (recommended) <ul><li>推薦，最乾淨、最通用的起點 <ul><li>基本 <code>Nuxt</code> 專案結構</li><li>不預設任何額外功能（幾乎純 Nuxt）</li><li>適合自行決定技術棧</li></ul></li></ul></li><li>module – Nuxt module <ul><li>不是做網站，是做『套件』 <ul><li>開發 <code>Nuxt</code> 插件（npm 套件）</li><li>提供其他 <code>Nuxt</code> 專案使用</li></ul></li></ul></li><li>ui – App using Nuxt UI <ul><li>內建 UI 元件庫的應用模板 <ul><li><code>Nuxt UI</code>（類似 Ant Design / Chakra）</li><li>預設 <code>UI component</code>（button、modal…）</li></ul></li></ul></li></ul></li></ul></details></li><li><h3 id="進入-my-nuxt-app-專案目錄" tabindex="-1">進入 <code>my-nuxt-app</code> 專案目錄 <a class="header-anchor" href="#進入-my-nuxt-app-專案目錄" aria-label="Permalink to &quot;進入 `my-nuxt-app` 專案目錄&quot;">​</a></h3><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-nuxt-app</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><h3 id="安裝相關依賴套件" tabindex="-1">安裝相關依賴套件 <a class="header-anchor" href="#安裝相關依賴套件" aria-label="Permalink to &quot;安裝相關依賴套件&quot;">​</a></h3><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><h3 id="運行開發環境" tabindex="-1">運行開發環境 <a class="header-anchor" href="#運行開發環境" aria-label="Permalink to &quot;運行開發環境&quot;">​</a></h3><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ul><p>（雖然文章對結構可能沒有逐一詳述，但這些是 Nuxt 專案的標準配置。）</p><h2 id="_3-nuxt-cli-常用指令" tabindex="-1">3. Nuxt CLI 常用指令 <a class="header-anchor" href="#_3-nuxt-cli-常用指令" aria-label="Permalink to &quot;3. Nuxt CLI 常用指令&quot;">​</a></h2><p>在專案目錄下記得使用 <code>npx</code> 來執行 <code>nuxi</code></p><ul><li><h3 id="nuxi-init" tabindex="-1">nuxi init <a class="header-anchor" href="#nuxi-init" aria-label="Permalink to &quot;nuxi init&quot;">​</a></h3><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nuxi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">create</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [dir]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>用來初始化一個 <code>Nuxt</code> 專案，等價 <code>nuxi create</code> 指令。</p><blockquote><p><code>dir</code> 可以填字串作為專案與資料夾名稱，也可以填寫完整路徑來建立專案目錄。</p></blockquote></li><li><h3 id="nuxi-dev" tabindex="-1">nuxi dev <a class="header-anchor" href="#nuxi-dev" aria-label="Permalink to &quot;nuxi dev&quot;">​</a></h3><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nuxi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--open, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-o</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] [--port, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>當我們輸入 <code>npm run dev -- -o</code> 時，其實是依據 <code>package.json</code> 中的 <code>scripts</code> 執行 <code>nuxt dev -o</code>。</p><blockquote><ul><li><code>-o</code>：服務啟動後開啟瀏覽器</li><li><code>-p</code>：將預設的 <code>Port:3000</code> 調整為其他數值，如：<code>npm run dev -- -o -p 3001</code></li></ul></blockquote></li><li><h3 id="nuxi-cleanup" tabindex="-1">nuxi cleanup <a class="header-anchor" href="#nuxi-cleanup" aria-label="Permalink to &quot;nuxi cleanup&quot;">​</a></h3><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nuxi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clean</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cleanup</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>nuxi clean</code> 等價 <code>nuxi cleanup</code> 指令，用來刪除 <code>Nuxt</code> 自動產生的檔案和緩存，包括：</p><ul><li><code>.nuxt</code></li><li><code>.output</code></li><li><code>dist</code></li><li><code>node_modules/.vite</code></li><li><code>node_modules/.cache</code></li></ul></li><li><h3 id="nuxi-upgrade" tabindex="-1">nuxi upgrade <a class="header-anchor" href="#nuxi-upgrade" aria-label="Permalink to &quot;nuxi upgrade&quot;">​</a></h3><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nuxi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--force</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-f]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>用來將目前專案的 <code>Nuxt 3</code> 升級至最新的版本</p><ul><li><code>-f</code>：如果有一些可能行為調整或不相容的情況，可以再依據實際情境搭配 <code>-f</code> 參數來強制更新。</li></ul></li></ul>',10)])])}const k=a(l,[["render",t]]);export{r as __pageData,k as default};
